function isOpen() {
  const now = new Date();
  const day = now.getDay();
  const t = now.getHours() * 60 + now.getMinutes();
  const s = (a,b) => t >= a*60 && t < b*60;
  if (day>=1&&day<=4) return s(11,14)||s(18,22);
  if (day===5) return s(11,14)||s(18,24);
  if (day===6||day===0) return s(18,24);
  return false;
}

