function SnackPage({ onBack }) {
  const [activeTab,setActiveTab]=useState("kebab");
  const [cart,setCart]=useState([]);
  const [ordered,setOrdered]=useState(false);
  const partner=PARTNERS[0];
  const open=isOpen();
  const currentCat=MENU.find(c=>c.id===activeTab);

  return (
    <>
      <div className="snack-hero" style={{paddingTop:100}}>
        <img className="snack-hero-bg" src={partner.img} alt={partner.name}/>
        <div className="snack-hero-overlay"/>
        <div className="snack-hero-content">
          <button className="snack-back fb" onClick={onBack}>← Retour</button>
          <div className="snack-name fd">{partner.name}</div>
          <div className="snack-meta">
            <div className="snack-meta-item fb">📍 {partner.address}</div>
            <div className="snack-meta-item fb">📞 {partner.phone.replace(/(\d{2})(?=\d)/g,"$1 ").trim()}</div>
            <div className="snack-meta-item fb" style={{color:open?"#7FD4A0":"#F09090"}}>{open?"🟢 Ouvert":"🔴 Fermé"}</div>
          </div>
        </div>
      </div>
      <div style={{background:"#F7F3EE",padding:"72px 48px"}}>
        <FadeUp>
          <div className="sec-tag fb">Horaires</div>
          <div className="sec-title fd" style={{marginBottom:32}}>Quand <em>passer</em> ?</div>
          <div className="hours-grid">
            {partner.hours.map(h=>(
              <div className="hours-card" key={h.day}>
                <div className="hours-day fd">{h.day}</div>
                {h.slots.map(s=><div className="hours-slot fb" key={s}>{s}</div>)}
              </div>
            ))}
          </div>
        </FadeUp>
        <FadeUp>
          <div className="sec-tag fb">Menu</div>
          <div className="sec-title fd">Composez votre <em>commande</em></div>
          <div className="tabs">
            {MENU.map(c=>(
              <button key={c.id} className={"tab fb "+(activeTab===c.id?"active":"")} onClick={()=>setActiveTab(c.id)}>{c.cat}</button>
            ))}
          </div>
          <div className="menu-grid">
            {currentCat?.isTacos
              ?<TacosCard onAdd={e=>setCart(p=>[...p,e])}/>
              :currentCat?.items?.map(item=>(
                <MenuItem key={item.id} item={item} onAdd={e=>setCart(p=>[...p,e])}/>
              ))
            }
          </div>
        </FadeUp>
        {(cart.length>0||ordered)&&(
          <FadeUp>
            <Cart
              cart={cart}
              onRemove={i=>setCart(p=>p.filter((_,idx)=>idx!==i))}
              onOrder={async ()=>{const total=cart.reduce((s,c)=>s+c.item.price+(c.cheddar?1.5:0),0);const now=new Date();const heure=now.getHours().toString().padStart(2,"0")+":"+now.getMinutes().toString().padStart(2,"0");const details=cart.map(c=>c.item.name+(c.garnitures?.length?" : "+c.garnitures.join(", "):"")+(c.sauces?.length?" - sauces: "+c.sauces.join(", "):"")).join(", ");await supabase.from("orders").insert({partner_id:partner.id,partner_name:partner.name,order_type:"commande",formula_name:cart.map(c=>c.item.name).join(", "),client_name:name,pickup_time:heure,client_price:total,partner_price:total*0.8,zack_commission:total*0.2});await fetch("https://api.elevenlabs.io/v1/convai/twilio/outbound-call",{method:"POST",headers:{"xi-api-key":import.meta.env.VITE_ELEVENLABS_API_KEY,"Content-Type":"application/json"},body:JSON.stringify({agent_id:"agent_3801kpzkh35qfsaad81savww2sh0",agent_phone_number_id:"phnum_0601kq5q01tves1syvmw2kzk5jnd",to_number:"+33625951075",conversation_initiation_client_data:{dynamic_variables:{client_name:name,details:details,heure:heure}}})});window.location.href="tel:"+partner.phone;setOrdered(true);}}
              ordered={ordered}
            />
            {ordered&&(
              <button className="btn-primary fb" style={{margin:"24px auto 0",display:"flex"}}
                onClick={()=>{setOrdered(false);setCart([]);}}>
                Nouvelle commande
              </button>
            )}
          </FadeUp>
        )}
      </div>
      <footer className="footer" style={{background:"#F7F3EE"}}>
        <div className="footer-logo fd">local<em>ly</em></div>
        <div className="footer-copy fb">© 2025 · Bordeaux · Tous droits réservés</div>
      </footer>
    </>
  );
}

export default function App() {
  const [page,setPage]=useState("home");
  const [activeCat,setActiveCat]=useState(null);
  useEffect(()=>{window.scrollTo(0,0);},[page]);
  function navigate(target,catId=null){if(catId)setActiveCat(catId);setPage(target);}
  return (
    <div style={{background:"#F7F3EE",minHeight:"100vh"}}>
      <style>{CSS}</style>
      <nav className="nav">
        <div className="logo fd" onClick={()=>setPage("home")}>local<em>ly</em></div>
        <ul className="nav-links">
          <li><a onClick={()=>setPage("home")}>Accueil</a></li>
          {page==="category"&&<li><a onClick={()=>setPage("home")}>Catégories</a></li>}
          {page==="snack"&&<li><a onClick={()=>setPage("category")}>Restauration</a></li>}
        </ul>
        <button className="nav-cta fb" onClick={()=>setPage("home")}>
          {page==="home"?"Explorer →":"Accueil"}
        </button>
      </nav>
      {page==="home"&&<HomePage onNavigate={navigate}/>}
      {page==="category"&&<CategoryPage categoryId={activeCat} onBack={()=>setPage("home")} onNavigate={p=>setPage(p)}/>}
      {page==="snack"&&<SnackPage onBack={()=>setPage("category")}/>}
    </div>
  );
}

